INSERT INTO restaurants (id, name, address, location_link, latitude, longitude, location_tag_id, uploaded_by, rating, summary, description, price_min, price_max, created_at) VALUES
(32, '육장정', NULL, 'https://place.map.kakao.com/309142826', 37.51056259, 127.1088392, 23, 4, 4, '갈비 4대와 꼬들한 면은 라면을 먹으면서 부자가 된 기분을 느끼게 해준다. 마지막에 기름기를 완벽히 날려주는 자몽이 있다.\n\n송리단길이라는 단어와 뭔가 어울리지 않는 육개장집. 갈비 4대와 꼬들한 면은 라면을 먹으면서 부자가 된 기분을 느끼게 해준다. 마지막에 기름기를 완벽히 날려주는 자몽은 사장님 부부의 센스를 느끼게 해주는 디테일이다.', '육개장', 10000, 14000, NULL),
(33, '꼬따', NULL, 'https://place.map.kakao.com/143081516', 37.50736402, 127.1145552, 23, 4, 4, '화덕에서 구워 빵에서 불향이 남\n\n이탈리아에서 피자를 배워오신 사장님이 화덕에서 구워주시는 진짜 나폴리 피자. 빵에서 계속 불향이 나서 엣지까지 재미있는 피자였습니다', '나폴리 피자', 10000, 14000, NULL),
(34, '산월수제비', NULL, 'https://place.map.kakao.com/16271793', 37.4953432, 127.0639369, 21, 4, 4, '멸치베이스에 딱 밀가루 반죽으로 칼국수랑 수제비를 넣은 정말 기본적인 배치지만 딱 기본에 충실하게 먹고 싶을때 가기 좋습니당.', NULL, 10000, 14000, NULL),
(35, '강남교자칼국수', '서울 서초구 강남대로69길 11 삼미빌딩', 'https://place.map.kakao.com/11891754', 37.50145964, 127.0241926, 22, 4, 4, '명동교자에 비해 더 깔끔한 맛이 일품입니다', NULL, 10000, 14000, NULL),
(36, '임병주산동칼국수', '서울 서초구 강남대로37길 65', 'https://place.map.kakao.com/25038356', 37.48456983, 127.0300304, 22, 4, 4, '해산물+채소 베이스라 부담없이 잘 넘어갑니다', NULL, 10000, 14000, NULL),
(37, '베테랑칼국수', '전북 전주시 완산구 경기전길 135', 'https://place.map.kakao.com/15482458', 35.81345582, 127.1514303, 15, 4, 4, '쫄면도 맛있고 칼국수도 무난합니다', NULL, 10000, 14000, NULL),
(38, '백암왕순대', '서울 서초구 사평대로55길 139 미성빌딩', 'https://place.map.kakao.com/9817288', 37.51001637, 127.0200014, 22, 4, 4, '국물이 깔끔하고 건더기가 많음.\n\n이투스 정승제T의 최애 순댓국이라는 백암 왕순대. 호기롭게 주문한 얼큰이탕 (특)은 ‘얼큰‘하지는 않았다. 국물이 깔끔하고 건더기가 아주 많은점은 좋았음.', NULL, 10000, 14000, NULL),
(39, '브릭오븐', '서울 강남구 강남대로102길 31 2층', 'https://place.map.kakao.com/19037502', 37.50309869, 127.0277805, 21, 4, 4, '본토 스타일\n\n시험이 끝난것을 기념하여 오랜만에 식당 모임을 가졌습니다. 미국인 형님들의 바이브를 느끼며 본토 스타일의 피자와 지티를 먹었습니다. 그리고 프로슈토 풍기 피자에 도전해주신 부원들께 진심으로 감사드리며 다음에도 맛있는 음식으로 찾아뵙겠습니다.', '프로슈토 풍기', 10000, 14000, NULL),
(40, '비밀베이커리', '서울 송파구 올림픽로 269 프리미엄 롯데슈퍼 지하1층 비밀베이커리', 'https://place.map.kakao.com/1329233080', 37.51442975, 127.1006465, 23, 4, 4, '가성비 샌드위치 맛집 .재료간의 조화가 아주 좋으며, 가벼운 한끼 식사로 추천합니다.\n\n가성비 샌드위치 맛집 ‘비밀 베이커리’입니다. 6-8천원 가격대에서 만원 중반대 샌드위치 퀄리티를 그대로 느낄 수 있는 아주 훌륭한 맛집입니다. 재료간의 조화가 아주 좋으며, 가벼운 한끼 식사로 추천합니다.', NULL, 10000, 14000, NULL),
(41, '원조손칼국수', '서울 성북구 종암로 113 국승호치과의원', 'https://place.map.kakao.com/11486122', 36.37324058, 127.320327, 29, 4, 4, '한식의 강자를 찾기 상당히 어려운 학교 주변 권역에서 묵직한 한방을 가진 맛집입니다.\n\n갈축 끝나는 날 가본 맛집인데 이제서야 소개를 합니다. 한식의 강자를 찾기 상당히 어려운 학교 주변 권역에서 묵직한 한방을 가진 맛집입니다. 전식으로 주시는 동치미국물은 적절히 찬 온도감에 통쾌하다싶은 시원한 맛이 좋습니다. 칼국수의 육수는 사골베이스와 채소의 단맛이 묵직하게 때려박는 일품 그 자체인 맛입니다. 만두는 부추와 고기가 넉넉히 들어있고 (당면 없는걸로 봐서 가게에서 만들었음) 간 또한 타이트해서 좋았습니다.', NULL, 10000, 14000, NULL),
(42, '지우관', '서울 성동구 뚝섬로 427-15 B1층', 'https://place.map.kakao.com/1060315738', 37.53842876, 127.057772, 26, 4, 4, '총평: 잘하는 집은 맞음. 가격대비 만족도 좋음.하지만 회장 본인이 중식에 대한 기준이 매애애우 까다로운 사람이라 회장한테는 soso\n\n성수동의 아주 안쪽에 있는 중화요리집 ‘지우관’에 갔다 왔습니다. 딤섬, 요리, 우육면 등을 파는 곳입니다. 동파육 덮밥은 고추잡채덮밥에서 응용된 야채볶음을 올려주어 식사 자체를 완주하기에는 아주 좋으나 동파육 자체의 맛은 그럭저럭입니다. 딤섬은 유바에다가 새우를 넣은 춘권인데 식감이 재밌고 새우가 제법 많이 들었습니다. 우육면은 고수의 향이 강하고 (그야 제가 고수를 많이 넣어서) 국물이 무난하였습니다.', NULL, 10000, 14000, NULL),
